+#[derive(Debug, PartialEq, Eq)]
+#[allow(clippy::struct_field_names)]
+struct ComplianceEvaluation {
+    missing_unit_ids: Vec<&'static str>,
+    missing_e2e_ids: Vec<&'static str>,
+    missing_log_levels: Vec<&'static str>,
